    public function get_settings_fields() {
        return [
            ['key'=>'client_id','label'=>__('AppKey','wp-omni-auth'),'type'=>'text','default'=>'','class'=>'regular-text','description'=>__('DingTalk Open Platform → App Details → Credentials & Basic Info → AppKey','wp-omni-auth')],
            ['key'=>'client_secret','label'=>__('AppSecret','wp-omni-auth'),'type'=>'password','default'=>'','class'=>'regular-text'],
        ];
    }
    public function get_authorization_url($state) {
        return 'https://login.dingtalk.com/oauth2/auth?'.http_build_query(['client_id'=>$this->get_client_id(),'redirect_uri'=>$this->get_redirect_uri(),'response_type'=>'code','scope'=>'openid','state'=>$state,'prompt'=>'consent']);
    }
    public function get_access_token($code) {
        $r=$this->remote_post('https://api.dingtalk.com/v1.0/oauth2/accessToken',['headers'=>['Content-Type'=>'application/json'],'body'=>wp_json_encode(['clientId'=>$this->get_client_id(),'clientSecret'=>$this->get_client_secret(),'code'=>$code,'grantType'=>'authorization_code'])]);
        if(empty($r)||isset($r['code'])&&$r['code']!==0){return null;}
        return $r['accessToken']??null;
    }
    public function get_user_data($access_token) {
        $r=$this->remote_get('https://api.dingtalk.com/v1.0/oauth2/userinfo',['headers'=>['x-acs-dingtalk-access-token'=>$access_token]]);
        if(!empty($r)){$r['id']=$r['sub']??$r['unionId']??$r['openId']??'';}
        return $r;
    }
    public function get_email_from_user_data($user_data) { return $user_data['email']??''; }
    public function get_button_color() { return '#0089FF'; }
    private function get_redirect_uri(){return add_query_arg('wpomni_callback',$this->slug,wp_login_url());}
    private function log($m,$d=null){WPOmniAuth_Manager::debug_log($m,$d,$this->get_name());}
}
